  1	import * as React from 'react';
  2	import {
  3	  Drawer,
  4	  DrawerContent,
  5	  DrawerContentBody,
  6	  PageSection,
  7	} from '@patternfly/react-core';
  8	import { FormikProps } from 'formik';
  9	import * as _ from 'lodash';
 10	import { useTranslation } from 'react-i18next';
 11	import { PipelineModel } from '../../models';
 12	import {
 13	  PipelineKind,
 14	  PipelineTask,
 15	  SelectedBuilderTask,
 16	  TaskKind,
 17	} from '../../types';
 18	import { STATUS_KEY_NAME_ERROR, UpdateOperationType } from './const';
 19	import { sanitizeToForm, sanitizeToYaml } from './form-switcher-validation';
 20	import {
 21	  useExplicitPipelineTaskTouch,
 22	  useFormikFetchAndSaveTasks,
 23	} from './hooks';
 24	import RemoveTaskModal from './modals';
 25	import PipelineBuilderFormEditor from './PipelineBuilderFormEditor';
 26	import PipelineBuilderHeader from './PipelineBuilderHeader';
 27	import TaskSidebar from './task-sidebar/TaskSidebar';
 28	import {
 29	  CleanupResults,
 30	  PipelineBuilderTaskGroup,
 31	  UpdateOperationRenameTaskData,
 32	  PipelineBuilderFormikValues,
 33	  TaskType,
 34	  TaskSearchCallback,
 35	  EditorType,
 36	} from './types';
 37	import { applyChange } from './update-utils';
 38	
 39	import './PipelineBuilderForm.scss';
 40	import CodeEditorField from './CodeEditorField';
 41	import FormFooter from '../pipelines-details/multi-column-field/FormFooter';
 42	import { FlexForm, FormBody } from './form-utils';
 43	import SyncedEditorField from './SyncedEditorField';
 44	import PipelineQuickSearch from '../task-quicksearch/PipelineQuickSearch';
 45	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
 46	
 47	type PipelineBuilderFormProps = FormikProps<PipelineBuilderFormikValues> & {
 48	  existingPipeline: PipelineKind;
 49	  namespace: string;
 50	};
 51	
 52	const PipelineBuilderForm: React.FC<PipelineBuilderFormProps> = (props) => {
 53	  const { t } = useTranslation('plugin__pipelines-console-plugin');
 54	  const launchModal = useModal();
 55	  const [selectedTask, setSelectedTask] =
 56	    React.useState<SelectedBuilderTask>(null);
 57	  const selectedTaskRef = React.useRef<SelectedBuilderTask>(null);
 58	  selectedTaskRef.current = selectedTask;
 59	  const contentRef = React.useRef<HTMLDivElement>(null);
 60	
 61	  const {
 62	    existingPipeline,
 63	    status,
 64	    isSubmitting,
 65	    dirty,
 66	    handleReset,
 67	    handleSubmit,
 68	    errors,
 69	    namespace,
 70	    setFieldValue,
 71	    values: { editorType, formData, taskResources },
 72	    validateForm,
 73	  } = props;
 74	  useFormikFetchAndSaveTasks(namespace, validateForm);
 75	  useExplicitPipelineTaskTouch();
 76	
 77	  const statusRef = React.useRef(status);
 78	  const [menuOpen, setMenuOpen] = React.useState<boolean>(false);
 79	  const savedCallback = React.useRef(() => {});
 80	
 81	  statusRef.current = status;
 82	
 83	  const resetSelectedTask = (): void => {
 84	    setSelectedTask(null);
 85	    selectedTaskRef.current = null;
 86	  };
 87	  const onTaskSearch: TaskSearchCallback = (callback: () => void): void => {
 88	    setMenuOpen(true);
 89	    resetSelectedTask();
 90	    savedCallback.current = callback;
 91	  };
 92	  const onTaskSelection = (
 93	    task: PipelineTask,
 94	    resource: TaskKind,
 95	    isFinallyTask: boolean,
 96	  ) => {
 97	    const builderNodes = isFinallyTask ? formData.finallyTasks : formData.tasks;
 98	    setSelectedTask({
 99	      isFinallyTask,
100	      taskIndex: builderNodes.findIndex(({ name }) => name === task.name),
101	      resource,
102	    });
103	  };
104	
105	  const updateTasks = (changes: CleanupResults): void => {
106	    const { tasks, listTasks, finallyTasks, finallyListTasks, loadingTasks } =
107	      changes;
108	    setFieldValue('formData', {
109	      ...formData,
110	      tasks,
111	      listTasks,
112	      loadingTasks,
113	      finallyTasks,
114	      finallyListTasks,
115	    });
116	  };
117	
118	  const nodeType: TaskType = selectedTask?.isFinallyTask
119	    ? 'finallyTasks'
120	    : 'tasks';
121	  const selectedId = formData[nodeType][selectedTask?.taskIndex]?.name;
122	  const selectedIds = selectedId ? [selectedId] : [];
123	
124	  const taskGroup: PipelineBuilderTaskGroup = {
125	    tasks: formData.tasks,
126	    listTasks: formData.listTasks,
127	    loadingTasks: formData.loadingTasks,
128	    highlightedIds: selectedIds,
129	    finallyTasks: formData.finallyTasks,
130	    finallyListTasks: formData.finallyListTasks,
131	  };
132	
133	  const onUpdateTasks = (updatedTaskGroup, op) => {
134	    updateTasks(applyChange(updatedTaskGroup, op, namespace));
135	  };
136	
137	  const closeSidebarAndHandleReset = React.useCallback(() => {
138	    resetSelectedTask();
139	    handleReset();
140	  }, [handleReset]);
141	
142	  const LAST_VIEWED_EDITOR_TYPE_USERSETTING_KEY =
143	    'pipeline.pipelineBuilderForm.editor.lastView';
144	
145	  const formEditor = (
146	    <PipelineBuilderFormEditor
147	      hasExistingPipeline={!!existingPipeline}
148	      taskGroup={taskGroup}
149	      taskResources={taskResources}
150	      onTaskSelection={onTaskSelection}
151	      onTaskSearch={onTaskSearch}
152	      onUpdateTasks={onUpdateTasks}
153	    />
154	  );
155	
156	  const yamlEditor = (
157	    <CodeEditorField
158	      name="yamlData"
159	      model={PipelineModel}
160	      showSamples={!existingPipeline}
161	      onSave={handleSubmit}
162	    />
163	  );
164	
165	  const closeRef = React.useCallback(() => {
166	    if (!!contentRef.current && !!selectedTask) {
167	      const currentSelection: SelectedBuilderTask = selectedTaskRef.current;
168	      setTimeout(() => {
169	        if (
170	          currentSelection?.taskIndex === selectedTaskRef.current?.taskIndex &&
171	          currentSelection?.isFinallyTask ===
172	            selectedTaskRef.current?.isFinallyTask
173	        ) {
174	          // Clicked on itself or on a non-node
175	          setSelectedTask(null);
176	        }
177	      }, 0); // let the click logic flow through
178	    }
179	  }, [selectedTask]);
180	
181	  const handleRemoveTask = React.useCallback(
182	    async (taskName: string) => {
183	      setSelectedTask(null);
184	      updateTasks(
185	        applyChange(
186	          taskGroup,
187	          { type: UpdateOperationType.REMOVE_TASK, data: { taskName } },
188	          namespace,
189	        ),
190	      );
191	    },
192	    [namespace, taskGroup, updateTasks],
193	  );
194	
195	  return (
196	    <Drawer isExpanded={!!selectedTask} position="right">
197	      <DrawerContent
198	        panelContent={
199	          selectedTask ? (
200	            <TaskSidebar
201	              // Intentional remount when selection changes
202	              key={selectedTask?.taskIndex}
203	              onClose={() => setSelectedTask(null)}
204	              resourceList={formData.resources || []}
205	              workspaceList={formData.workspaces || []}
206	              errorMap={status?.tasks || {}}
207	              onRenameTask={(data: UpdateOperationRenameTaskData) => {
208	                updateTasks(
209	                  applyChange(
210	                    taskGroup,
211	                    {
212	                      type: UpdateOperationType.RENAME_TASK,
213	                      data,
214	                    },
215	                    namespace,
216	                  ),
217	                );
218	              }}
219	              onRemoveTask={(taskName: string) => {
220	                launchModal(RemoveTaskModal, {
221	                  taskName,
222	                  onRemove: () => handleRemoveTask(taskName),
223	                });
224	              }}
225	              selectedData={selectedTask}
226	            />
227	          ) : null
228	        }
229	      >
230	        <DrawerContentBody onClick={closeRef}>
231	          <div
232	            className="opp-pipeline-builder ocs-quick-search-modal__no-backdrop"
233	            ref={contentRef}
234	          >
235	            <PipelineBuilderHeader />
236	            <FlexForm
237	              className="opp-pipeline-builder-form"
238	              onSubmit={handleSubmit}
239	            >
240	              <PageSection isFilled variant="light">
241	                <FormBody
242	                  flexLayout
243	                  disablePaneBody
244	                  className="opp-pipeline-builder-form"
245	                >
246	                  <PipelineQuickSearch
247	                    namespace={namespace}
248	                    viewContainer={contentRef.current}
249	                    isOpen={menuOpen}
250	                    callback={savedCallback.current}
251	                    setIsOpen={(open) => setMenuOpen(open)}
252	                    onUpdateTasks={onUpdateTasks}
253	                    taskGroup={taskGroup}
254	                  />
255	                  <SyncedEditorField
256	                    noMargin
257	                    name="editorType"
258	                    formContext={{
259	                      name: 'formData',
260	                      editor: formEditor,
261	                      label: t('Pipeline builder'),
262	                      sanitizeTo: (yamlPipeline: PipelineKind) =>
263	                        sanitizeToForm(formData, yamlPipeline),
264	                    }}
265	                    yamlContext={{
266	                      name: 'yamlData',
267	                      editor: yamlEditor,
268	                      sanitizeTo: () =>
269	                        sanitizeToYaml(formData, namespace, existingPipeline),
270	                    }}
271	                    lastViewUserSettingKey={
272	                      LAST_VIEWED_EDITOR_TYPE_USERSETTING_KEY
273	                    }
274	                  />
275	                </FormBody>
276	              </PageSection>
277	              <FormFooter
278	                handleReset={closeSidebarAndHandleReset}
279	                errorMessage={status?.submitError}
280	                isSubmitting={isSubmitting}
281	                submitLabel={existingPipeline ? t('Save') : t('Create')}
282	                disableSubmit={
283	                  editorType === EditorType.YAML
284	                    ? !dirty || !_.isEmpty(errors) || !!status?.submitError
285	                    : !dirty ||
286	                      !_.isEmpty(errors) ||
287	                      !_.isEmpty(status?.tasks) ||
288	                      !_.isEmpty(status?.[STATUS_KEY_NAME_ERROR]) ||
289	                      formData.tasks.length === 0 ||
290	                      formData.loadingTasks.length > 0
291	                }
292	                resetLabel={t('Cancel')}
293	                sticky
294	              />
295	            </FlexForm>
296	          </div>
297	        </DrawerContentBody>
298	      </DrawerContent>
299	    </Drawer>
300	  );
301	};
302	
303	export default PipelineBuilderForm;

